sql:
SELECT company_name
FROM insurance_companies
ORDER BY license_date DESC;

SELECT user_id, COUNT(*) AS total_quotes
FROM quotes
GROUP BY user_id;

external_knowledge:
- In this metaphor, 'leaves' represent 'claims';
- 'Tree' is a metaphor for the 'insurance company';
- 'Aspire Advantage' is the name of the insurance company in question.

sql:
SELECT COUNT(DISTINCT c.claim_id) AS total_claims_paid
FROM claims c
INNER JOIN claim_payments cp ON c.claim_id = cp.claim_id;

SELECT COUNT(DISTINCT c.claim_id) AS total_claims_by_paid_users
FROM claims c
JOIN payments p ON c.user_id = p.user_id;

SELECT COUNT(DISTINCT v.vehicle_id) AS total_vehicles
FROM vehicles v
INNER JOIN payments p ON v.user_id = p.user_id;

SELECT SUM(premium) AS total_premium
FROM quotes
WHERE quote_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT COUNT(claim_id) AS total_claims
FROM claims
WHERE strftime('%Y', claim_date) = '2023';
